var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"무, 무슨 거래인데?","JPN":"ど、どういう取引なんだ？","ENG":"W-what kind of deal is it?","TWN":"那、那是什麼交易？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"서, 설마 이 구속구를 채운 것도 그런 이유였나?","JPN":"ま、まさかこの拘束具をつけたのもそういう理由だったとか？","ENG":"D-don't tell me that's why you put these restraints on me?","TWN":"難、難道這個束具也是為了這個理由？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"미안하지만, 난 누구처럼 웃통 깐 근육 아저씨 수발 들 생각은 추호도 없거든?","JPN":"悪いけど、あたしは誰かさんみたいに上半身丸出しのマッチョなおっさんの世話をするつもりはこれっぽちもないから。","ENG":"Sorry, but I'm not about to wait hand and foot on some shirtless muscle-head like you-know-who.","TWN":"抱歉，我可沒像某人有伺候裸上身肌肉大叔的想法。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"왜 저를 바라보시는 거죠?","JPN":"どうして私を見るのですか？","ENG":"Why are you looking at me?","TWN":"妳為什麼那樣看我？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그리고, 그런 이유 아니거든요?!","JPN":"それに、そんな理由ではありません！","ENG":"And that is absolutely not the reason!","TWN":"而且也不是那種理由吧？！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 그런 거래였으면 말을 꺼내지도 않았을 거야.","JPN":"ハハハ！　そんな取引だったら、最初から口にするほどのものでもないさ。","ENG":"Gah hah hah! If that were the deal, I wouldn't have brought it up.","TWN":"哈哈哈！如果是那種理由，我根本不會開口。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 아가씨라면 분명… 충분히 응할 수 있는 조건이라고 생각하거든.","JPN":"だがお嬢さんならきっと……十分に応えられる条件だと思う。","ENG":"But I think... you'll find the conditions perfectly acceptable.","TWN":"但如果是小姐，我相信……妳完全可以接受這條件。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"프론트 베이는 현재 예상치 못한 검은 범람으로 위기 상황이야.","JPN":"フロントベイは今、想定外の黒い氾濫という危機的状況に直面している。","ENG":"Front Bay is in crisis from an unexpected Black Flood.","TWN":"前灣目前因為意想不到的黑色洪災陷入危機。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"격벽엔 수많은 침식체가 몰려들어 틈을 파고들고 있고, 이를 막을 병사는 턱없이 부족하지.","JPN":"隔壁には数多くの侵食体が押し寄せて隙間から入り込もうとしているが、それを食い止めるための兵士がとにかく足りない。","ENG":"Countless C.O.s are swarming the bulwark and breaking through, and we're severely short on soldiers to hold them off.","TWN":"隔離牆聚集了無數侵蝕體試圖突破，但阻止它們的兵力嚴重不足。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"도시는 중앙의 관리국 본부를 기준으로 여러 섹터로 나뉘어져 있어.","JPN":"都市は中央の管理局本部を基準として、いくつかのセクターに分けられている。","ENG":"The city is divided into multiple sectors, with the Administration HQ at the center.","TWN":"城市以中央的管理局本部為中心，向外劃分多個區域。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 그렇게 나뉜 섹터를 기준으로 격벽을 구분하지.","JPN":"そして、そうやって分けられたセクターごとに隔壁を区別している。","ENG":"And those sectors define the bulwark divisions.","TWN":"隔離牆也是依照各區域設置。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨가 할 일은 간단해.","JPN":"お嬢さんにやってもらいたいことは、いたって簡単さ。","ENG":"Your job is simple.","TWN":"小姐要做的事很簡單。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"각 섹터에서 들어오는 지원 요청을 받아 그쪽의 일을 해결하는 거지.","JPN":"各セクターから入ってくる支援要請を受け、それを解決するんだ。","ENG":"You'll take on the support requests coming from each sector and resolve the problems there.","TWN":"接收各區域的支援請求，解決那裡的問題。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 도시의 지원 요청을 모두 해결한다면…….","JPN":"都市の支援要請をすべて解決できれば……","ENG":"And if you manage to complete all the city's requests...","TWN":"當解決所有城市的支援請求後……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨는 자유의 몸을 되찾고, 프론트 베이도 사람들에게 돌려줄 수 있지.","JPN":"お嬢さんは晴れて自由の身となり、フロントベイも取り戻せる。","ENG":"You'll gain your freedom, and Front Bay can be returned to its people.","TWN":"小姐就能恢復自由，也能將前灣還給人民。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"만약 실패한다면……?","JPN":"もし失敗したら……？","ENG":"And if I fail...?","TWN":"如果失敗呢……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫, 뭘 당연한 소리를 하고 그러나?","JPN":"ハハッ、何を分かりきったことを。","ENG":"Haha, isn't it obvious?","TWN":"哈哈，妳說什麼廢話呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리 다 함께 손잡고 죽는 거지.","JPN":"みんな仲良く死ぬだけだ。","ENG":"We all join hands and die together.","TWN":"我們大家一起手牽手死掉啊。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 그건 거래가 아니라 협박이잖아.","JPN":"くそ、もはや取引どころか、だだの脅迫じゃねぇか。","ENG":"Damn it, that's not a deal. That's a threat.","TWN":"可惡。這不是交易，而是威脅。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님이 그 정도로 배려해 주신 것도 고맙게 생각하세요.","JPN":"シニア様がここまで配慮してくださったことに感謝すべきです。","ENG":"You should be grateful the Senior offered even that level of mercy.","TWN":"Senior應該要感謝他這麼體貼。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"원래라면 아케론에서 평생을 썩었야 했던 거, 아시죠?","JPN":"本来ならアケロンで一生を終えるはずだったのはご存じですよね？","ENG":"You know you would be rotting in Acheron for life under normal circumstances.","TWN":"妳原本應該在黃泉度過一生，不是嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"흥, 지들이 멋대로 결정해 놓고는.","JPN":"ふん、自分たちで勝手に決めたくせに。","ENG":"Hmph, deciding everything on their own and acting like they're doing me a favor.","TWN":"哼，還不是你們擅自作主。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그건 그렇고, 너는 왜 내 옆에서 쫑알거리는 거야?","JPN":"それはそうとして、お前なんであたしの横でぶつぶつ言ってるわけ？","ENG":"Anyway, why are you yapping next to me?","TWN":"對了，你為什麼在我身邊嘰嘰喳喳？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"시니어 옆에서 시끄럽게 잔소리나 하러 가라고.","JPN":"がみがみ小言言うのは、シニアの隣に行ってやれよ。","ENG":"Go nag next to the Senior or something.","TWN":"去Senior旁邊鬧吧。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저는 당신의 출력을 통제할 의무가 있어요.","JPN":"私にはあなたの出力を統制する義務があります。","ENG":"I'm responsible for controlling your output.","TWN":"我有義務控制妳的輸出。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님도 허락한 사안이니까, 도망칠 생각은 안 하시는 게 좋을걸요?","JPN":"シニア様もお許しになった件ですので、逃げるなんて夢にも思わないことです。","ENG":"And since the Senior approved it, you'd better not think about running.","TWN":"Senior也允許了，所以最好別想逃跑"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장… 이렇게 답답한 상황은 딱 질색인데.","JPN":"くそ……こういう窮屈な状況って苦手なんだけどな。","ENG":"Damn it... I hate being boxed in like this.","TWN":"可惡……這種讓人窒息的情況真討厭。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}}]`);export{e as default};